// // This D flip-flop synchronizes the input D to the output Q on a falling edge of the clock and resets to 1 on a rising edge of the reset signal.
module d_ff(
    input clk,
    input reset,
    input D,
    output reg Q
);

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            Q <= 0;
        end else begin
            Q <= D;
        end
    end

endmodule
